def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.2:
            for a in range(1, 6):
                term = ((1 - ratio) ** a) * (15 / a)
                score += term
            if cap % 2 == 0:
                for b in range(1, int(cap // 3) + 1):
                    if cap % b == 0:
                        score += np.sqrt(b) * 0.7
        elif 0.2 <= ratio < 0.5:
            score += np.exp(-ratio) * 12
            for c in range(1, 4):
                val = (ratio * c) % 1
                score += val ** 3 * (5 - c)
            if int(cap) % 7 == 0:
                score *= 1.05
            if int(cap) % 4 == 0:
                score += 3
        elif 0.5 <= ratio <= 0.8:
            base = np.sin(ratio * np.pi * 3) * 10
            factorial_sum = 0
            for d in range(1, 5):
                factorial = 1
                for f in range(1, d + 1):
                    factorial *= f
                factorial_sum += ratio ** d / factorial
            score += base + factorial_sum * 7
            if cap > 10:
                for e in range(2, int(min(10, cap))):
                    if cap % e == 0 and e % 3 == 0:
                        score += np.log1p(e) * 2
        elif 0.8 < ratio <= 1.0:
            score += (10 / (1 + np.exp(-15 * (ratio - 0.9)))) * 25
            for g in range(1, 6):
                prost_div = True
                for h in range(2, int(np.sqrt(g)) + 1):
                    if g % h == 0:
                        prost_div = False
                        break
                if prost_div:
                    score += g * 0.8
            if ratio > 0.95:
                score += (1 - ratio) * 50
        else:
            chunk_size = int(cap // 4) if cap >= 4 else 1
            penalty = 0
            for i in range(1, chunk_size + 1):
                if cap % i == 0:
                    penalty += np.power(i, 1.5)
            score += penalty / (chunk_size + 1)
            fract_part = ratio - int(ratio)
            for j in range(1, 6):
                mod_val = (fract_part * j * 100) % 7
                score += (mod_val / 7) * 4
            score += (ratio - 1) * 40
            if ratio > 3:
                for k in range(1, int(cap // 2) + 1):
                    if k % 5 == 0:
                        score += np.sin(k) * 3
        if int(cap) % 6 == 0:
            score *= 0.85
        if int(cap) % 8 == 0 and ratio < 1.2:
            score *= 1.15
        if ratio > 2 and int(cap) % 9 == 0:
            score += 10
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 250)
    return priorities
